{"code": "import json

# Read the full business data from file
file_path = locals()['var_functions.query_db:8']
with open(file_path, 'r') as f:
    businesses = json.load(f)

# Filter businesses that accept credit cards
credit_card_businesses = []
for business in businesses:
    if 'attributes' in business and business['attributes'] != 'None' and business['attributes'] is not None:
        attributes = business['attributes']
        if isinstance(attributes, dict) and 'BusinessAcceptsCreditCards' in attributes:
            if attributes['BusinessAcceptsCreditCards'] == 'True':
                credit_card_businesses.append(business)

print('Total credit card businesses:', len(credit_card_businesses))

# Extract categories from descriptions
from collections import defaultdict
category_count = defaultdict(int)

for business in credit_card_businesses:
    if 'description' in business and business['description']:
        desc = business['description'].lower()

        # Extract category patterns
        categories = []
        import re

        # Look for comma-separated lists of capitalized words
        # This pattern matches common category listings
        patterns = [
            r'fields of ([^\.\n]+)',
            r'category of [\'"]([^\'"]+)[\'"]',
            r'services in ([^\.\n]+)',
            r'offers a range of services including ([^\.\n]+)',
            r'for anyone seeking ([^\.\n]+)'
        ]

        for pattern in patterns:
            matches = re.findall(pattern, desc, re.IGNORECASE)
            for match in matches:
                # Split by comma, 'and', or '&'
                cats = re.split(r',|\band\b|&', match)
                for cat in cats:
                    cat = cat.strip()
                    if cat:
                        # Remove leading stop words
                        cat = re.sub(r'^\s*(in|of|for|and|or|the|a|an)\s+', '', cat, flags=re.IGNORECASE)
                        cat = cat.strip()
                        if cat:
                            categories.append(cat)

        # If no explicit pattern found, look for capitalized category lists
        if not categories:
            # Find patterns like "Hair Salons, Beauty & Spas, Hair Stylists"
            cap_words = re.findall(r'([A-Z][a-z]+(?:\s+(?:&\s+)?[A-Z][a-z]+)*(?:,\s*[A-Z][a-z]+(?:\s+(?:&\s+)?[A-Z][a-z]+)*)*)', business['description'])
            for item in cap_words:
                if ',' in item:
                    cats = item.split(',')
                    for cat in cats:
                        cat = cat.strip()
                        if cat and len(cat) > 3:
                            categories.append(cat.lower())

        # Count categories
        for cat in categories:
            if cat and len(cat) > 2:
                category_count[cat] += 1

        business['categories'] = categories

# Find top category
if category_count:
    top_category = max(category_count.items(), key=lambda x: x[1])
    print('Top category:', top_category)
else:
    top_category = (None, 0)
    print('No categories found')

print('Total unique categories:', len(category_count))

# Save results
result = {
    'credit_card_count': len(credit_card_businesses),
    'category_count': dict(category_count),
    'top_category_name': top_category[0],
    'top_category_count': top_category[1]
}

print('__RESULT__:')
print(json.dumps(result))
"}

