                credit_card_businesses.append(business)

print('Total credit card businesses:', len(credit_card_businesses))

# Look at description format
print('Sample description:')
if credit_card_businesses:
    print(credit_card_businesses[0].get('description', 'No desc'))

# Simple category extraction
from collections import defaultdict
category_count = defaultdict(int)

for business in credit_card_businesses:
    if 'description' in business and business['description']:
        desc = business['description']

        # Try to extract categories from common phrases
        desc_lower = desc.lower()

        # Look for patterns like "category of 'X, Y, Z'" or similar
        import re

        # Pattern 1: quoted strings with commas (most reliable)
        quoted_patterns = re.findall(r"['\"]([^'\"]+)['\"]", desc)
        for quoted in quoted_patterns:
            if ',' in quoted:
                parts = quoted.split(',')
                for part in parts:
                    part = part.strip()
                    if part and len(part) > 3:
                        category_count[part.lower()] += 1

        # Pattern 2: Look for "including X, Y, Z" or "such as X, Y, Z"
        include_patterns = re.findall(r'(?:including|such as|like) ([A-Z][^\n\.]+)', desc)
        for pattern in include_patterns:
            if ',' in pattern:
                parts = pattern.split(',')
                for part in parts:
                    part = part.strip()
                    # Clean up end punctuation
                    part = re.sub(r'[\.;]$', '', part)
                    if part and len(part) > 3:
                        category_count[part.lower()] += 1

        # Pattern 3: If still no match, look at the last part after category/fields/services keywords
        if not quoted_patterns and not include_patterns:
            # Try to find comma-separated lists near the end
            # Look for multiple capitalized words separated by commas
            generic_patterns = re.findall(r'([A-Z][a-z]+(?:,\s*[A-Z][a-z]+)+)', desc)
            for generic in generic_patterns:
                parts = generic.split(',')
                for part in parts:
                    part = part.strip()
                    if part and len(part) > 3:
                        # Remove common endings
                        part = re.sub(r'(\s+and\s+.*|\s+or\s+.*)$', '', part)
                        category_count[part.lower()] += 1

# Show results
top_categories = sorted(category_count.items(), key=lambda x: x[1], reverse=True)[:15]
print('\nTop 15 categories:')
for cat, count in top_categories:
    print(f"  {cat}: {count}")

if top_categories:
    top_category = top_categories[0]
    print(f'\nTop category: {top_category[0]} with {top_category[1]} businesses')
else:
    top_category = (None, 0)
    print('\nNo categories found')

result = {
    'credit_card_count': len(credit_card_businesses),
    'top_category_name': top_category[0],
    'top_category_count': top_category[1]
}

