for business in credit_card_businesses:
    if 'description' in business and business['description']:
        desc = business['description'].lower()

        # Extract category patterns
        categories = []
        import re

        # Look for comma-separated lists of capitalized words
        # This pattern matches common category listings
        patterns = [
            r'fields of ([^\.\n]+)',
            r'category of [\'"]([^\'"]+)[\'"]',
            r'services in ([^\.\n]+)',
            r'offers a range of services including ([^\.\n]+)',
            r'for anyone seeking ([^\.\n]+)'
        ]

        for pattern in patterns:
            matches = re.findall(pattern, desc, re.IGNORECASE)
            for match in matches:
                # Split by comma, 'and', or '&'
                cats = re.split(r',|\band\b|&', match)
                for cat in cats:
                    cat = cat.strip()
                    if cat:
                        # Remove leading stop words
                        cat = re.sub(r'^\s*(in|of|for|and|or|the|a|an)\s+', '', cat, flags=re.IGNORECASE)
                        cat = cat.strip()
                        if cat:
